'use client';

import React, { useState, useCallback } from 'react';
import {
  Box,
  Button,
  Card,
  CardContent,
  Typography,
  TextField,
  Stack,
  IconButton,
  List,
  ListItem,
  ListItemText,
  MenuItem,
  Select,
  InputLabel,
  FormControl,
  Avatar,
  useMediaQuery,
  useTheme,
} from '@mui/material';
import { useDropzone } from 'react-dropzone';
import InsertDriveFileIcon from '@mui/icons-material/InsertDriveFile';
import DeleteIcon from '@mui/icons-material/Delete';
import PictureAsPdfIcon from '@mui/icons-material/PictureAsPdf';
import DescriptionIcon from '@mui/icons-material/Description';
import axios from 'axios';

import { Canvas } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';
import { motion } from 'framer-motion';
import TableChartIcon from '@mui/icons-material/TableChart';
import TextSnippetIcon from '@mui/icons-material/TextSnippet';

const renderPreview = (file: File) => {
  const ext = file.name.split('.').pop()?.toLowerCase();

  if (file.type.startsWith('image/')) {
    return (
      <Avatar
        variant="rounded"
        src={URL.createObjectURL(file)}
        alt={file.name}
        sx={{ width: 50, height: 50 }}
      />
    );
  }

  if (ext === 'pdf') {
    return (
      <Avatar sx={{ bgcolor: '#f44336', width: 50, height: 50 }}>
        <PictureAsPdfIcon />
      </Avatar>
    );
  }

  if (ext === 'doc' || ext === 'docx') {
    return (
      <Avatar sx={{ bgcolor: '#1976d2', width: 50, height: 50 }}>
        <DescriptionIcon />
      </Avatar>
    );
  }

  if (ext === 'xls' || ext === 'xlsx') {
    return (
      <Avatar sx={{ bgcolor: '#2e7d32', width: 50, height: 50 }}>
        <TableChartIcon />
      </Avatar>
    );
  }

  if (ext === 'txt') {
    return (
      <Avatar sx={{ bgcolor: '#616161', width: 50, height: 50 }}>
        <TextSnippetIcon />
      </Avatar>
    );
  }
}


// ✅ 3D Cube component
function UploadCube({ isDrag }: { isDrag: boolean }) {
  return (
    <mesh rotation={[0.4, 0.6, 0]}>
      <boxGeometry args={[2, 2, 2]} />
      <meshStandardMaterial
        color={isDrag ? '#ff4081' : '#6c63ff'}
        emissive={isDrag ? '#ff4081' : 'black'}
      />
    </mesh>
  );
}

// ✅ Liquid Progress component
function LiquidProgress({ progress }: { progress: number }) {
  return (
    <div
      style={{
        width: 150,
        height: 150,
        borderRadius: '50%',
        overflow: 'hidden',
        border: '3px solid #6c63ff',
        position: 'relative',
        margin: '0 auto',
      }}>
      <motion.div
        style={{
          position: 'absolute',
          bottom: 0,
          left: 0,
          width: '100%',
          background: 'linear-gradient(180deg, #6c63ff, #9a8cff)',
        }}
        animate={{ height: `${progress}%` }}
        transition={{ ease: 'easeInOut', duration: 0.8 }}
      />
      <div
        style={{
          position: 'absolute',
          top: '40%',
          width: '100%',
          textAlign: 'center',
          fontWeight: 'bold',
          fontSize: 20,
        }}>
        {progress}%
      </div>
    </div>
  );
}

export default function ModernUploadPage() {
  const [files, setFiles] = useState<File[]>([]);
  const [customerName, setCustomerName] = useState('');
  const [phone, setPhone] = useState('');
  const [note, setNote] = useState('');
  const [category, setCategory] = useState<string>('นามบัตร');
  const [uploading, setUploading] = useState(false);
  const [progress, setProgress] = useState(0);

  const categories = ['นามบัตร', 'ตรายาง', 'ถ่ายเอกสาร & ปริ้นงาน', 'สติ๊กเกอร์'];

  // ✅ responsive hooks
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('sm'));
  const isTablet = useMediaQuery(theme.breakpoints.between('sm', 'md'));

  // ✅ Drag & Drop Handler
  const onDrop = useCallback((acceptedFiles: File[]) => {
    setFiles(prev => [...prev, ...acceptedFiles]);
  }, []);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({ onDrop });

  const handleRemoveFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const handleUpload = async () => {
    if (files.length === 0) return;
    const formData = new FormData();
    files.forEach(file => formData.append('files', file));
    formData.append('category', category);
    formData.append('customerName', customerName);
    formData.append('phone', phone);
    formData.append('note', note);

    try {
      setUploading(true);
      setProgress(0);

      await axios.post(`${process.env.NEXT_PUBLIC_API_URL}/upload`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
        onUploadProgress: e => {
          if (e.total) setProgress(Math.round((e.loaded * 100) / e.total));
        },
      });

      alert('Upload Success!');
      setFiles([]);
      setCustomerName('');
      setPhone('');
      setNote('');
    } catch (err) {
      alert('Upload Failed!');
    } finally {
      setUploading(false);
    }
  };

  // ✅ Preview Renderer
// ✅ Preview Renderer
const renderPreview = (file: File) => {
  const ext = file.name.split('.').pop()?.toLowerCase();

  if (file.type.startsWith('image/')) {
    return (
      <Avatar
        variant="rounded"
        src={URL.createObjectURL(file)}
        alt={file.name}
        sx={{ width: 50, height: 50 }}
      />
    );
  }

  if (ext === 'pdf') {
    return (
      <Avatar sx={{ bgcolor: '#f44336', width: 50, height: 50 }}>
        <PictureAsPdfIcon />
      </Avatar>
    );
  }

  if (ext === 'doc' || ext === 'docx') {
    return (
      <Avatar sx={{ bgcolor: '#1976d2', width: 50, height: 50 }}>
        <DescriptionIcon />
      </Avatar>
    );
  }

  if (ext === 'xls' || ext === 'xlsx' || ext === 'csv') {
    return (
      <Avatar sx={{ bgcolor: '#2e7d32', width: 50, height: 50 }}>
        <TableChartIcon />
      </Avatar>
    );
  }

  if (ext === 'txt') {
    return (
      <Avatar sx={{ bgcolor: '#616161', width: 50, height: 50 }}>
        <TextSnippetIcon />
      </Avatar>
    );
  }

  // ⬇️ default case
  return (
    <Avatar sx={{ bgcolor: '#9e9e9e', width: 50, height: 50 }}>
      <InsertDriveFileIcon />
    </Avatar>
  );
};


  return (
    <Box
      sx={{
        minHeight: '100vh',
        bgcolor: '#f4f6f9',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        p: isMobile ? 1 : 3,
      }}>
      <Card
        sx={{
          width: '100%',
          maxWidth: isMobile ? '95%' : isTablet ? 600 : 700,
          borderRadius: '24px',
          boxShadow: '0 10px 30px rgba(0,0,0,0.08)',
          background: 'linear-gradient(180deg, #ffffff 0%, #f9f9ff 100%)',
        }}>
        <CardContent sx={{ p: isMobile ? 2 : 4 , mt: 2 }}>
          {/* Header */}
          <Box textAlign="center" mb={isMobile ? 2 : 4}>
            <Typography variant={isMobile ? 'h6' : 'h5'} fontWeight="bold">
              📂 อัพโหลดไฟล์งานพิมพ์
            </Typography>
            <Typography variant="body2" color="text.secondary">
              ลากไฟล์มาวางที่นี่ หรือคลิกเพื่อเลือกไฟล์
            </Typography>
          </Box>

          {/* ✅ ถ้าอัพโหลดอยู่ → แสดง Liquid Progress */}
          {uploading ? (
            <Box textAlign="center" my={3}>
              <LiquidProgress progress={progress} />
              <Typography variant="body2" mt={2}>
                กำลังอัพโหลด...
              </Typography>
            </Box>
          ) : (
            // ✅ ถ้าไม่ได้อัพโหลด → แสดง 3D Drop Zone
            <Box
              {...getRootProps()}
              sx={{
                height: 300,
                borderRadius: '16px',
                textAlign: 'center',
                cursor: 'pointer',
                overflow: 'hidden',
              }}>
              <input {...getInputProps()} />
              
              <Canvas camera={{ position: [4, 4, 4] }}>
                <ambientLight intensity={0.5} />
                <directionalLight position={[5, 5, 5]} />
                <UploadCube isDrag={isDragActive} />
                <OrbitControls enableZoom={false} />
              </Canvas>
              <Typography mt={1}>
                {isDragActive ? 'ปล่อยไฟล์ได้เลย...' : 'ลากไฟล์มาที่นี่ หรือคลิกเพื่อเลือก'}
              </Typography>
              
            </Box>
          )}

          {/* File List */}
          {files.length > 0 && (
            <List dense sx={{ mt: 2 }}>
              {files.map((f, index) => (
                <ListItem
                  key={index}
                  secondaryAction={
                    <IconButton edge="end" onClick={() => handleRemoveFile(index)}>
                      <DeleteIcon color="error" />
                    </IconButton>
                  }>
                  {renderPreview(f)}
                  <ListItemText
                    sx={{
                      ml: 2,
                      overflow: 'hidden',
                      textOverflow: 'ellipsis',
                      whiteSpace: 'nowrap',
                    }}
                    primary={f.name}
                    secondary={`${(f.size / 1024).toFixed(1)} KB`}
                  />
                </ListItem>
              ))}
            </List>
          )}

          

          {/* Customer Info */}
          <Stack spacing={2} mt={3}>
            <FormControl fullWidth>
              <InputLabel id="category-label">ประเภทงาน</InputLabel>
              <Select
                labelId="category-label"
                value={category}
                onChange={e => setCategory(e.target.value)}>
                {categories.map(cat => (
                  <MenuItem key={cat} value={cat}>
                    {cat}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>
            <TextField
              label="ชื่อลูกค้า"
              value={customerName}
              onChange={e => setCustomerName(e.target.value)}
              fullWidth
              size={isMobile ? 'small' : 'medium'}
            />
            <TextField
              label="เบอร์โทรศัพท์"
              value={phone}
              onChange={e => setPhone(e.target.value)}
              fullWidth
              size={isMobile ? 'small' : 'medium'}
            />
            <TextField
              label="Note"
              value={note}
              onChange={e => setNote(e.target.value)}
              fullWidth
              multiline
              rows={isMobile ? 2 : 3}
              size={isMobile ? 'small' : 'medium'}
            />
          </Stack>

          {/* Submit Button */}
          <Button
            variant="contained"
            fullWidth
            sx={{ mt: 4, py: isMobile ? 1 : 1.5, borderRadius: '12px' }}
            onClick={handleUpload}
            disabled={files.length === 0 || !customerName || !phone || uploading}>
            {uploading ? `Uploading... ${progress}%` : '🚀 อัพโหลดไฟล์'}
          </Button>
        </CardContent>
      </Card>
    </Box>
  );
}
